<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  :root {
    color-scheme: dark;
    --bg: #101218;
    --panel: #191d27;
    --panel2: #222838;
    --text: #edf1f7;
    --muted: #9ca8ba;
    --accent: #7c9cff;
  }

  * { box-sizing: border-box; }

  body {
    margin: 0;
    min-height: 100vh;
    background:
      radial-gradient(circle at 50% 0%, #20283a 0, var(--bg) 48rem),
      var(--bg);
    color: var(--text);
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 24px;
  }

  .app {
    width: min(94vw, 720px);
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 18px;
  }

  h1 {
    margin: 0;
    font-size: clamp(1.45rem, 4vw, 2.2rem);
    letter-spacing: .04em;
    font-weight: 750;
  }

  .subtitle {
    margin-top: -10px;
    color: var(--muted);
    font-size: .9rem;
  }

  .toolbar {
    width: 100%;
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 9px;
    flex-wrap: wrap;
    padding: 12px;
    border: 1px solid #303848;
    border-radius: 16px;
    background: rgba(25, 29, 39, .92);
    box-shadow: 0 12px 36px rgba(0,0,0,.25);
  }

  button {
    border: 0;
    border-radius: 999px;
    color: var(--text);
    background: var(--panel2);
    padding: 10px 15px;
    min-width: 92px;
    font: inherit;
    font-size: .9rem;
    cursor: pointer;
    transition: transform .12s ease, filter .12s ease, box-shadow .12s ease;
    box-shadow: 0 3px 8px rgba(0,0,0,.25);
  }

  button:hover { filter: brightness(1.18); transform: translateY(-1px); }
  button:active { transform: translateY(1px) scale(.98); }

  button.selected {
    outline: 2px solid var(--accent);
    outline-offset: 2px;
    background: #35446c;
  }

  #clear {
    background: #643c4b;
    margin-left: 7px;
  }

  .canvas-wrap {
    padding: 10px;
    border-radius: 18px;
    background: #0a0d12;
    box-shadow:
      0 20px 55px rgba(0,0,0,.45),
      inset 0 0 0 1px #303746;
  }

  #sand {
    display: block;
    width: min(78vw, 620px);
    height: min(78vw, 620px);
    min-width: 400px;
    min-height: 400px;
    max-width: 620px;
    max-height: 620px;
    border-radius: 9px;
    background: #11151d;
    image-rendering: pixelated;
    cursor: crosshair;
    touch-action: none;
  }

  .hint {
    color: var(--muted);
    font-size: .82rem;
  }

  @media (max-width: 470px) {
    body { padding: 10px; }
    #sand {
      width: 400px;
      height: 400px;
      transform: scale(calc((100vw - 20px) / 420));
      transform-origin: top center;
      margin-bottom: calc(400px * (1 - (100vw - 20px) / 420));
    }
    .toolbar { gap: 6px; }
    button { min-width: 78px; padding: 8px 10px; }
  }
</style>
</head>
<body>
<main class="app">
  <h1>Falling Sand</h1>
  <div class="subtitle">Paint a tiny world and watch it move</div>

  <div class="toolbar" aria-label="Materials">
    <button id="mat-sand" data-material="sand">Sand</button>
    <button id="mat-water" data-material="water">Water</button>
    <button id="mat-wall" data-material="wall">Wall</button>
    <button id="mat-acid" data-material="acid">Acid</button>
    <button id="mat-empty" data-material="empty">Eraser</button>
    <button id="clear">Clear</button>
  </div>

  <div class="canvas-wrap">
    <canvas id="sand" width="600" height="600" aria-label="Falling sand simulation"></canvas>
  </div>
  <div class="hint">Drag on the canvas to paint materials</div>
</main>

<script>
(() => {
  "use strict";

  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d", { alpha: false });
  const W = 100, H = 100;
  const names = new Set(["empty", "sand", "water", "wall", "acid"]);
  const grid = Array.from({ length: H }, () => Array(W).fill("empty"));
  const moved = Array.from({ length: H }, () => Array(W).fill(false));

  let selected = "sand";
  let drawing = false;
  let seed = 0x5eeda11;

  function randomBit() {
    seed = (seed * 1664525 + 1013904223) >>> 0;
    return (seed >>> 30) & 1;
  }

  function inside(x, y) {
    return x >= 0 && x < W && y >= 0 && y < H;
  }

  function interior(x, y) {
    return x > 0 && x < W - 1 && y >= 0 && y < H - 1;
  }

  function moveCell(x1, y1, x2, y2) {
    if (!inside(x2, y2) || grid[y2][x2] !== "empty") return false;
    grid[y2][x2] = grid[y1][x1];
    grid[y1][x1] = "empty";
    moved[y1][x1] = true;
    moved[y2][x2] = true;
    return true;
  }

  function swapCell(x1, y1, x2, y2) {
    const t = grid[y1][x1];
    grid[y1][x1] = grid[y2][x2];
    grid[y2][x2] = t;
    moved[y1][x1] = true;
    moved[y2][x2] = true;
  }

  function dissolveAround(x, y) {
    const targets = [[x, y + 1], [x - 1, y], [x + 1, y]];
    for (const [tx, ty] of targets) {
      // Keep the outermost boundary solid.
      if (tx <= 0 || tx >= W - 1 || ty < 0 || ty >= H - 1) continue;
      if (grid[ty][tx] === "sand" || grid[ty][tx] === "wall") {
        grid[ty][tx] = "empty";
        moved[ty][tx] = true;
      }
    }
  }

  function trySand(x, y) {
    const below = grid[y + 1][x];

    if (below === "empty") {
      moveCell(x, y, x, y + 1);
      return;
    }

    // Sink into liquid while displacing it sideways locally. This prevents
    // liquid from being carried upward through a falling column.
    if (below === "water" || below === "acid") {
      const first = randomBit() ? -1 : 1;
      const second = -first;
      for (const dx of [first, second]) {
        const sx = x + dx;
        if (interior(sx, y + 1) && grid[y + 1][sx] === "empty") {
          grid[y + 1][sx] = below;
          grid[y + 1][x] = "sand";
          grid[y][x] = "empty";
          moved[y][x] = moved[y + 1][x] = moved[y + 1][sx] = true;
          return;
        }
      }
      // If completely surrounded, the explicit sink/swap rule applies.
      swapCell(x, y, x, y + 1);
      return;
    }

    const first = randomBit() ? -1 : 1;
    const second = -first;
    for (const dx of [first, second]) {
      const nx = x + dx;
      if (interior(nx, y + 1) && grid[y + 1][nx] === "empty") {
        moveCell(x, y, nx, y + 1);
        return;
      }
    }
  }

  function tryLiquid(x, y, type) {
    if (grid[y + 1][x] === "empty") {
      moveCell(x, y, x, y + 1);
      return;
    }

    const first = randomBit() ? -1 : 1;
    const second = -first;
    for (const dx of [first, second]) {
      const nx = x + dx;
      if (interior(nx, y) && grid[y][nx] === "empty") {
        moveCell(x, y, nx, y);
        return;
      }
    }
  }

  function step() {
    for (let y = 0; y < H; y++) moved[y].fill(false);

    // Bottom-row-up is essential: a particle can only be acted on once.
    for (let y = H - 2; y >= 0; y--) {
      const leftToRight = randomBit() === 0;
      for (let i = 1; i < W - 1; i++) {
        const x = leftToRight ? i : W - 1 - i;
        if (moved[y][x]) continue;

        const type = grid[y][x];
        if (type === "acid") dissolveAround(x, y);

        if (type === "sand") trySand(x, y);
        else if (type === "water") tryLiquid(x, y, "water");
        else if (type === "acid") tryLiquid(x, y, "acid");
      }
    }
  }

  const colors = {
    empty: "#11151d",
    sand: "#e6b85c",
    water: "#3e9be8",
    wall: "#727b8b",
    acid: "#9bea4e"
  };

  function render() {
    const cw = canvas.width / W;
    const ch = canvas.height / H;
    ctx.fillStyle = colors.empty;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        const type = grid[y][x];
        if (type !== "empty") {
          ctx.fillStyle = colors[type];
          ctx.fillRect(x * cw, y * ch, cw + .35, ch + .35);
        }
      }
    }

    // Subtle solid boundary indication.
    ctx.strokeStyle = "rgba(255,255,255,.08)";
    ctx.lineWidth = 2;
    ctx.strokeRect(1, 1, canvas.width - 2, canvas.height - 2);
  }

  function clearGrid() {
    for (let y = 0; y < H; y++) grid[y].fill("empty");
    render();
  }

  function paintAtEvent(e) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((e.clientX - rect.left) / rect.width * W);
    const y = Math.floor((e.clientY - rect.top) / rect.height * H);
    if (!interior(x, y)) return;
    grid[y][x] = selected;
    render();
  }

  document.querySelectorAll("[data-material]").forEach(button => {
    button.addEventListener("click", () => {
      selected = button.dataset.material;
      document.querySelectorAll("[data-material]").forEach(b =>
        b.classList.toggle("selected", b === button)
      );
    });
  });

  document.getElementById("clear").addEventListener("click", clearGrid);

  canvas.addEventListener("pointerdown", e => {
    drawing = true;
    canvas.setPointerCapture(e.pointerId);
    paintAtEvent(e);
  });
  canvas.addEventListener("pointermove", e => {
    if (drawing) paintAtEvent(e);
  });
  canvas.addEventListener("pointerup", () => drawing = false);
  canvas.addEventListener("pointercancel", () => drawing = false);
  canvas.addEventListener("pointerleave", e => {
    if (e.buttons === 0) drawing = false;
  });

  window.sim = {
    w: W,
    h: H,
    tick(n) {
      n = Math.max(0, Math.floor(Number(n) || 0));
      for (let i = 0; i < n; i++) step();
      render();
    },
    get(x, y) {
      x = Math.floor(x); y = Math.floor(y);
      return inside(x, y) ? grid[y][x] : undefined;
    },
    set(x, y, material) {
      x = Math.floor(x); y = Math.floor(y);
      if (inside(x, y) && names.has(material)) {
        grid[y][x] = material;
        render();
      }
    },
    clear: clearGrid
  };

  document.getElementById("mat-sand").classList.add("selected");
  render();

  let last = 0;
  function animate(time) {
    if (time - last > 45) {
      step();
      render();
      last = time;
    }
    requestAnimationFrame(animate);
  }
  requestAnimationFrame(animate);
})();
</script>
</body>
</html>
